package com.example.mixin;

import com.example.GlowManager;
import net.minecraft.client.network.AbstractClientPlayerEntity;
import net.minecraft.entity.Entity;
import org.spongepowered.asm.mixin.Mixin;
import org.spongepowered.asm.mixin.injection.At;
import org.spongepowered.asm.mixin.injection.Inject;
import org.spongepowered.asm.mixin.injection.callback.CallbackInfoReturnable;

@Mixin(Entity.class)
public class AbstractClientPlayerEntityMixin {
    @Inject(method = "setGlowing", at = @At("HEAD"), cancellable = true)
    private void onIsGlowingLocal(CallbackInfoReturnable<Boolean> cir) {
        AbstractClientPlayerEntity self = (AbstractClientPlayerEntity) (Object) this;
        if (GlowManager.has(self.getUuid())) {
            cir.setReturnValue(true);
        }
    }
}

package com.example.mixin;

import com.example.GlowManager;
import net.minecraft.client.network.AbstractClientPlayerEntity;
import org.spongepowered.asm.mixin.Mixin;
import org.spongepowered.asm.mixin.injection.At;
import org.spongepowered.asm.mixin.injection.Inject;
import org.spongepowered.asm.mixin.injection.callback.CallbackInfoReturnable;

@Mixin(AbstractClientPlayerEntity.class)
public class AbstractClientPlayerEntityMixin {
    @Inject(method = "isGlowing", at = @At("HEAD"), cancellable = true)
    private void onIsGlowing(CallbackInfoReturnable<Boolean> cir) {
        AbstractClientPlayerEntity self = (AbstractClientPlayerEntity) (Object) this;
        if (GlowManager.has(self.getUuid())) {
            cir.setReturnValue(true);
        }
    }
}

package com.somefrills;

import com.mojang.brigadier.CommandDispatcher;
import com.somefrills.commands.SomeFrillsCommand;
import com.somefrills.config.Features;
import com.somefrills.config.FrillsConfig;
import com.somefrills.events.ChatMsgEvent;
import com.somefrills.events.ClientDisconnectEvent;
import com.somefrills.events.OverlayMsgEvent;
import com.somefrills.events.PartyChatMsgEvent;
import com.somefrills.features.misc.Aliases;
import com.somefrills.misc.EntityCache;
import com.somefrills.misc.SkyblockData;
import com.somefrills.misc.Utils;
import io.github.notenoughupdates.moulconfig.gui.GuiContext;
import io.github.notenoughupdates.moulconfig.gui.GuiElementComponent;
import io.github.notenoughupdates.moulconfig.managed.GsonMapper;
import io.github.notenoughupdates.moulconfig.managed.ManagedConfig;
import io.github.notenoughupdates.moulconfig.platform.MoulConfigScreenComponent;
import meteordevelopment.orbit.EventBus;
import meteordevelopment.orbit.IEventBus;
import net.fabricmc.api.ClientModInitializer;
import net.fabricmc.fabric.api.client.command.v2.ClientCommandRegistrationCallback;
import net.fabricmc.fabric.api.client.command.v2.FabricClientCommandSource;
import net.fabricmc.fabric.api.client.message.v1.ClientReceiveMessageEvents;
import net.fabricmc.fabric.api.client.message.v1.ClientSendMessageEvents;
import net.fabricmc.fabric.api.client.networking.v1.ClientPlayConnectionEvents;
import net.fabricmc.loader.api.FabricLoader;
import net.minecraft.client.MinecraftClient;
import net.minecraft.client.gui.screen.Screen;
import net.minecraft.command.CommandRegistryAccess;
import net.minecraft.text.Text;
import net.minecraft.util.Util;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.IOException;
import java.lang.invoke.MethodHandles;
import com.google.gson.GsonBuilder;
import java.lang.reflect.Field;
import java.util.Set;
import java.util.Collections;
import java.util.IdentityHashMap;
import java.lang.reflect.Modifier;

public class Main implements ClientModInitializer {
    // Mod id - keep a local constant instead of relying on loader internals
    public static final String MOD_ID = "somefrills";

    public static final Logger LOGGER = LoggerFactory.getLogger(MOD_ID);
    public static MinecraftClient mc;
    public static IEventBus eventBus = new EventBus();
    public static ManagedConfig<FrillsConfig> config;

    public static void registerCommands(CommandDispatcher<FabricClientCommandSource> dispatcher, CommandRegistryAccess access) {
        SomeFrillsCommand.init(dispatcher);
    }

    public static void saveConfig() {
        LOGGER.info("SomeFrills is saving config...");
        if (config != null) {
            try {
                config.saveToFile();
            } catch (Exception e) {
                LOGGER.warn("Failed to save config file", e);
            }
        } else {
            LOGGER.warn("Attempted to save config but ManagedConfig is null");
        }
    }

    @Override
    public void onInitializeClient() {
        long start = Util.getMeasuringTimeMs();
        mc = MinecraftClient.getInstance();

        ClientCommandRegistrationCallback.EVENT.register(Main::registerCommands);

        ClientReceiveMessageEvents.ALLOW_GAME.register((message, overlay) -> {
            String msg = Utils.toPlain(message);

            if (overlay) {
                return !eventBus.post(new OverlayMsgEvent(message, msg)).isCancelled();
            }

            boolean cancelled = eventBus.post(new ChatMsgEvent(message, msg)).isCancelled();
            if (msg.startsWith("Party > ") && msg.contains(": ")) {
                int nameStart = msg.contains("]") && msg.indexOf("]") < msg.indexOf(":") ? msg.indexOf("]") : msg.indexOf(">");
                String[] clean = msg.replace(msg.substring(0, nameStart + 1), "").split(":", 2);
                String author = clean[0].trim(), content = clean[1].trim();
                cancelled = eventBus.post(new PartyChatMsgEvent(content, author)).isCancelled() || cancelled;
            }
            return !cancelled;
        });

        // Post ClientDisconnectEvent on Fabric disconnect and save config
        ClientPlayConnectionEvents.DISCONNECT.register((handler, client) ->
                eventBus.post(new ClientDisconnectEvent()));

        ClientSendMessageEvents.MODIFY_COMMAND.register(Aliases::convertCommand);

        var configFile = FabricLoader.getInstance().getConfigDir().resolve("somefrills.json").toFile();
        config = ManagedConfig.create(configFile, FrillsConfig.class);
        // Ensure moulconfig processes config fields before we access the instance or serialize it.
        try {
            config.rebuildConfigProcessor();
        } catch (Exception e) {
            LOGGER.warn("Failed to rebuild config processor", e);
        }
        FrillsConfig.instance = config.getInstance();
        // Save defaults so the config file is populated (helps debugging empty JSON)
        try {
            config.saveToFile();
        } catch (Exception e) {
            LOGGER.warn("Failed to write default config file", e);
        }

        // Diagnostic: reflectively inspect the config instance to see what fields and values are present
        try {
            LOGGER.info("Reflective dump of FrillsConfig instance:");
            Set<Object> visited = Collections.newSetFromMap(new IdentityHashMap<>());
            dumpObjectFields(FrillsConfig.instance, 0, visited);
        } catch (Exception e) {
            LOGGER.warn("Failed to reflectively dump config fields", e);
        }

        eventBus.registerLambdaFactory("com.somefrills",
                (lookupInMethod, klass) -> (MethodHandles.Lookup)
                        lookupInMethod.invoke(null, klass, MethodHandles.lookup()));

        eventBus.subscribe(SkyblockData.class);
        eventBus.subscribe(EntityCache.class);
        Features.init();

        // More diagnostics: class info and plain Gson serialization
        Class<?> instClass = config.getInstance().getClass();
        LOGGER.info("Config instance class: {}", instClass.getName());
        LOGGER.info("Config instance declared fields: {}", instClass.getDeclaredFields().length);
        LOGGER.info("FrillsConfig.class declared fields: {}", FrillsConfig.class.getDeclaredFields().length);

        var mapper = new GsonMapper<>(FrillsConfig.class);
        LOGGER.info("GsonMapper serialize: {}", mapper.serialize(config.getInstance()));

        var gson = new GsonBuilder().serializeNulls().setPrettyPrinting().create();
        LOGGER.info("Plain Gson serialize: {}", gson.toJson(config.getInstance()));

        LOGGER.info("It's time to get real, SomeFrills mod initialized in {}ms.", Util.getMeasuringTimeMs() - start);
    }

    private static void dumpObjectFields(Object obj, int indent, Set<Object> visited) {
        if (obj == null) {
            LOGGER.info("{}null", "  ".repeat(indent));
            return;
        }
        // Avoid revisiting the same object to prevent infinite recursion
        if (visited.contains(obj)) {
            LOGGER.info("{}<visited {}>", "  ".repeat(indent), obj.getClass().getSimpleName());
            return;
        }
        visited.add(obj);

        Class<?> cls = obj.getClass();
        for (Field f : cls.getDeclaredFields()) {
            // Skip synthetic/static fields and the FrillsConfig.instance field to avoid recursion
            if (f.isSynthetic() || Modifier.isStatic(f.getModifiers()) || f.getName().equals("instance")) continue;
            f.setAccessible(true);
            try {
                Object val = f.get(obj);
                // If the value is literally the global FrillsConfig.instance, skip to avoid infinite loop
                if (val == FrillsConfig.instance) {
                    LOGGER.info("{}{} {} = <FrillsConfig.instance>", "  ".repeat(indent), f.getType().getSimpleName(), f.getName());
                    continue;
                }
                LOGGER.info("{}{} {} = {}", "  ".repeat(indent), f.getType().getSimpleName(), f.getName(), val);

                if (val != null) {
                    Class<?> t = val.getClass();
                    if (!t.isPrimitive() && !t.isEnum() && !t.equals(String.class) && !Number.class.isAssignableFrom(t) && !Boolean.class.equals(t)) {
                        dumpObjectFields(val, indent + 1, visited);
                    }
                }
            } catch (IllegalAccessException e) {
                LOGGER.warn("Failed to access field {}", f.getName(), e);
            }
        }
    }
}

package com.somefrills;

import com.mojang.brigadier.CommandDispatcher;
import com.somefrills.commands.SomeFrillsCommand;
import com.somefrills.config.Features;
import com.somefrills.config.FrillsConfig;
import com.somefrills.events.ChatMsgEvent;
import com.somefrills.events.ClientDisconnectEvent;
import com.somefrills.events.OverlayMsgEvent;
import com.somefrills.events.PartyChatMsgEvent;
import com.somefrills.features.misc.Aliases;
import com.somefrills.misc.EntityCache;
import com.somefrills.misc.SkyblockData;
import com.somefrills.misc.Utils;
import io.github.notenoughupdates.moulconfig.gui.GuiContext;
import io.github.notenoughupdates.moulconfig.gui.GuiElementComponent;
import io.github.notenoughupdates.moulconfig.managed.GsonMapper;
import io.github.notenoughupdates.moulconfig.managed.ManagedConfig;
import io.github.notenoughupdates.moulconfig.platform.MoulConfigScreenComponent;
import meteordevelopment.orbit.EventBus;
import meteordevelopment.orbit.IEventBus;
import net.fabricmc.api.ClientModInitializer;
import net.fabricmc.fabric.api.client.command.v2.ClientCommandRegistrationCallback;
import net.fabricmc.fabric.api.client.command.v2.FabricClientCommandSource;
import net.fabricmc.fabric.api.client.message.v1.ClientReceiveMessageEvents;
import net.fabricmc.fabric.api.client.message.v1.ClientSendMessageEvents;
import net.fabricmc.fabric.api.client.networking.v1.ClientPlayConnectionEvents;
import net.fabricmc.loader.api.FabricLoader;
import net.minecraft.client.MinecraftClient;
import net.minecraft.client.gui.screen.Screen;
import net.minecraft.command.CommandRegistryAccess;
import net.minecraft.text.Text;
import net.minecraft.util.Util;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.IOException;
import java.lang.invoke.MethodHandles;
import com.google.gson.GsonBuilder;
import com.google.gson.JsonElement;
import com.google.gson.JsonSerializationContext;
import com.google.gson.JsonSerializer;
import java.lang.reflect.Type;
import io.github.notenoughupdates.moulconfig.observer.Property;
import java.io.FileWriter;
import java.lang.reflect.Field;
import java.util.Set;
import java.util.Collections;
import java.util.IdentityHashMap;
import java.lang.reflect.Modifier;

public class Main implements ClientModInitializer {
    // Mod id - keep a local constant instead of relying on loader internals
    public static final String MOD_ID = "somefrills";

    public static final Logger LOGGER = LoggerFactory.getLogger(MOD_ID);
    public static MinecraftClient mc;
    public static IEventBus eventBus = new EventBus();
    public static ManagedConfig<FrillsConfig> config;

    public static void registerCommands(CommandDispatcher<FabricClientCommandSource> dispatcher, CommandRegistryAccess access) {
        SomeFrillsCommand.init(dispatcher);
    }

    public static void saveConfig() {
        LOGGER.info("SomeFrills is saving config...");
        if (config != null) {
            try {
                config.saveToFile();
            } catch (Exception e) {
                LOGGER.warn("Failed to save config file", e);
            }
        } else {
            LOGGER.warn("Attempted to save config but ManagedConfig is null");
        }
    }

    @Override
    public void onInitializeClient() {
        long start = Util.getMeasuringTimeMs();
        mc = MinecraftClient.getInstance();

        ClientCommandRegistrationCallback.EVENT.register(Main::registerCommands);

        ClientReceiveMessageEvents.ALLOW_GAME.register((message, overlay) -> {
            String msg = Utils.toPlain(message);

            if (overlay) {
                return !eventBus.post(new OverlayMsgEvent(message, msg)).isCancelled();
            }

            boolean cancelled = eventBus.post(new ChatMsgEvent(message, msg)).isCancelled();
            if (msg.startsWith("Party > ") && msg.contains(": ")) {
                int nameStart = msg.contains("]") && msg.indexOf("]") < msg.indexOf(":") ? msg.indexOf("]") : msg.indexOf(">");
                String[] clean = msg.replace(msg.substring(0, nameStart + 1), "").split(":", 2);
                String author = clean[0].trim(), content = clean[1].trim();
                cancelled = eventBus.post(new PartyChatMsgEvent(content, author)).isCancelled() || cancelled;
            }
            return !cancelled;
        });

        // Post ClientDisconnectEvent on Fabric disconnect and save config
        ClientPlayConnectionEvents.DISCONNECT.register((handler, client) ->
                eventBus.post(new ClientDisconnectEvent()));

        ClientSendMessageEvents.MODIFY_COMMAND.register(Aliases::convertCommand);

        var configFile = FabricLoader.getInstance().getConfigDir().resolve("somefrills.json").toFile();
        config = ManagedConfig.create(configFile, FrillsConfig.class);
        // Ensure moulconfig processes config fields before we access the instance or serialize it.
        try {
            config.rebuildConfigProcessor();
        } catch (Exception e) {
            LOGGER.warn("Failed to rebuild config processor", e);
        }
        FrillsConfig.instance = config.getInstance();
        // Save defaults so the config file is populated (helps debugging empty JSON)
        try {
            config.saveToFile();
        } catch (Exception e) {
            LOGGER.warn("Failed to write default config file", e);
        }

        // Diagnostic: reflectively inspect the config instance to see what fields and values are present
        try {
            LOGGER.info("Reflective dump of FrillsConfig instance:");
            Set<Object> visited = Collections.newSetFromMap(new IdentityHashMap<>());
            dumpObjectFields(FrillsConfig.instance, 0, visited);
        } catch (Exception e) {
            LOGGER.warn("Failed to reflectively dump config fields", e);
        }

        eventBus.registerLambdaFactory("com.somefrills",
                (lookupInMethod, klass) -> (MethodHandles.Lookup)
                        lookupInMethod.invoke(null, klass, MethodHandles.lookup()));

        eventBus.subscribe(SkyblockData.class);
        eventBus.subscribe(EntityCache.class);
        Features.init();

        // More diagnostics: class info and plain Gson serialization
        Class<?> instClass = config.getInstance().getClass();
        LOGGER.info("Config instance class: {}", instClass.getName());
        LOGGER.info("Config instance declared fields: {}", instClass.getDeclaredFields().length);
        LOGGER.info("FrillsConfig.class declared fields: {}", FrillsConfig.class.getDeclaredFields().length);

        var mapper = new GsonMapper<>(FrillsConfig.class);
        String mapped = mapper.serialize(config.getInstance());
        LOGGER.info("GsonMapper serialize: {}", mapped);

        // Plain Gson for comparison
        var gson = new GsonBuilder().serializeNulls().setPrettyPrinting().create();
        String plain = gson.toJson(config.getInstance());
        LOGGER.info("Plain Gson serialize: {}", plain);

        // Gson that knows how to serialize Property<T> by delegating to its contained value
        var gsonWithProperty = new GsonBuilder()
                .registerTypeHierarchyAdapter(Property.class, new JsonSerializer<Property<?>>() {
                    @Override
                    public JsonElement serialize(Property<?> src, Type typeOfSrc, JsonSerializationContext context) {
                        try {
                            return context.serialize(src.get());
                        } catch (Exception e) {
                            // If getting the value fails, serialize null
                            return context.serialize(null);
                        }
                    }
                })
                .serializeNulls()
                .setPrettyPrinting()
                .create();

        String withProp = gsonWithProperty.toJson(config.getInstance());
        LOGGER.info("Gson with Property adapter serialize: {}", withProp);

        // If moulconfig's mapper produced an empty object, fall back to writing our gsonWithProperty output
        if (mapped != null && mapped.trim().equals("{}")) {
            try (FileWriter fw = new FileWriter(configFile)) {
                fw.write(withProp);
                LOGGER.info("Wrote fallback config using Gson with Property adapter to {}", configFile.getAbsolutePath());
            } catch (Exception e) {
                LOGGER.warn("Failed to write fallback config file", e);
            }
        }

        LOGGER.info("It's time to get real, SomeFrills mod initialized in {}ms.", Util.getMeasuringTimeMs() - start);
    }

    private static void dumpObjectFields(Object obj, int indent, Set<Object> visited) {
        if (obj == null) {
            LOGGER.info("{}null", "  ".repeat(indent));
            return;
        }
        // Avoid revisiting the same object to prevent infinite recursion
        if (visited.contains(obj)) {
            LOGGER.info("{}<visited {}>", "  ".repeat(indent), obj.getClass().getSimpleName());
            return;
        }
        visited.add(obj);

        Class<?> cls = obj.getClass();
        for (Field f : cls.getDeclaredFields()) {
            // Skip synthetic/static fields and the FrillsConfig.instance field to avoid recursion
            if (f.isSynthetic() || Modifier.isStatic(f.getModifiers()) || f.getName().equals("instance")) continue;
            f.setAccessible(true);
            try {
                Object val = f.get(obj);
                // If the value is literally the global FrillsConfig.instance, skip to avoid infinite loop
                if (val == FrillsConfig.instance) {
                    LOGGER.info("{}{} {} = <FrillsConfig.instance>", "  ".repeat(indent), f.getType().getSimpleName(), f.getName());
                    continue;
                }
                LOGGER.info("{}{} {} = {}", "  ".repeat(indent), f.getType().getSimpleName(), f.getName(), val);

                if (val != null) {
                    Class<?> t = val.getClass();
                    if (!t.isPrimitive() && !t.isEnum() && !t.equals(String.class) && !Number.class.isAssignableFrom(t) && !Boolean.class.equals(t)) {
                        dumpObjectFields(val, indent + 1, visited);
                    }
                }
            } catch (IllegalAccessException e) {
                LOGGER.warn("Failed to access field {}", f.getName(), e);
            }
        }
    }
}
